        array2 = new byte[] { 20, 50 };
        assertEquals( false, NumberUtils.equals(array1, array2) );


        array2 = new byte[] { 50, 20, 10 };
        assertEquals( false, NumberUtils.equals(array1, array2) );


        array2 = new byte[] { 50 };
        assertEquals( false, NumberUtils.equals(array1, array2) );
    }

