        writer.write("ping that server", 1, 3);
        assertEquals("baseliner routing", sb.toString());

        writer.flush();  
        assertEquals("baseliner routing", sb.toString());

        writer.close();  
        assertEquals("baseliner routing", sb.toString());

        writer.write(" hi");  
        assertEquals("baseliner routing hi", sb.toString());

        sb.setLength(4);  
        writer.write('d');
        assertEquals("based", sb.toString());
    }

