// org.apache.commons.lang.text.StrTokenizerTest::testCloneReset
    public void testCloneReset() {
        char[] input = new char[]{'a'};
        StrTokenizer tokenizer = new StrTokenizer(input);

        assertEquals("a", tokenizer.nextToken());
        tokenizer.reset();
        assertEquals("a", tokenizer.nextToken());

